using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip no longer defaults to system rendering.
        // Explicitly set the renderer to preserve the previous visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    [DesignerSerializationVisibility(DesignerSerializationVisibility.Visible)]
    public string DisplayName { get; set; }

    [DesignerSerializationVisibility(DesignerSerializationVisibility.Visible)]
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows a dropdown editor, guarding against the .NET 9 breaking change
    /// where passing null to DropDownControl now throws ArgumentNullException.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control dropdown)
    {
        if (dropdown is null)
            return;

        editorService.DropDownControl(dropdown);
    }
}

